import numpy as np
from typing import Iterable, Any, List, Optional
import random

def reservoir_sample(stream: Iterable[Any], k: int, seed: Optional[int] = None) -> List[Any]:
    rng = random.Random(seed)
    reservoir = []
    for i, item in enumerate(stream):
        if i < k:
            reservoir.append(item)
        else:
            # Replace a random element with probability k / (i+1)
            j = rng.randint(0, i)
            if j < k:
                reservoir[j] = item
    return reservoir

